from typing import List, Set, Dict, Tuple, Optional
from dataclasses import dataclass, field


@dataclass
class Statement:
    """几何命题。"""
    predicate: str
    args: Tuple[str, ...]

    def __str__(self):
        return f"{self.predicate} {' '.join(self.args)}"

    def __hash__(self):
        return hash((self.predicate, self.args))

    def __eq__(self, other):
        if not isinstance(other, Statement):
            return False
        return self.predicate == other.predicate and self.args == other.args


@dataclass
class ProofState:
    """证明状态。"""
    statements: Set[Statement] = field(default_factory=set)
    derived: Set[Statement] = field(default_factory=set)

    def add(self, stmt: Statement, is_derived: bool = False):
        """添加命题。"""
        self.statements.add(stmt)
        if is_derived:
            self.derived.add(stmt)

    def contains(self, stmt: Statement) -> bool:
        """检查是否包含命题。"""
        return stmt in self.statements

    def get_by_predicate(self, predicate: str) -> List[Statement]:
        """按谓词获取命题。"""
        return [s for s in self.statements if s.predicate == predicate]


class DeductionRule:
    """演绎规则。"""

    def __init__(self, name: str, premises: List[str], conclusions: List[str]):
        """初始化演绎规则。"""
        self.name = name
        self.premises = premises
        self.conclusions = conclusions

    def apply(self, state: ProofState) -> List[Statement]:
        """应用规则。"""
        new_statements = []

        premise_stmts = [self._parse_statement(p) for p in self.premises]
        conclusion_stmts = [self._parse_statement(c) for c in self.conclusions]

        bindings_list = self._find_bindings(state, premise_stmts)

        for bindings in bindings_list:
            for conc in conclusion_stmts:
                bound_args = tuple(bindings.get(arg, arg) for arg in conc.args)
                new_stmt = Statement(conc.predicate, bound_args)
                if not state.contains(new_stmt):
                    new_statements.append(new_stmt)

        return new_statements

    def _parse_statement(self, stmt_str: str) -> Statement:
        """解析语句。"""
        parts = stmt_str.split()
        if not parts:
            return Statement("", ())
        return Statement(parts[0], tuple(parts[1:]))

    def _find_bindings(
        self, state: ProofState, patterns: List[Statement]
    ) -> List[Dict[str, str]]:
        """查找参数绑定。"""
        if not patterns:
            return [{}]

        first_pattern = patterns[0]
        rest_patterns = patterns[1:]

        candidates = state.get_by_predicate(first_pattern.predicate)
        bindings_list = []

        for candidate in candidates:
            bindings = self._match_pattern(first_pattern.args, candidate.args)
            if bindings is not None:
                rest_bindings = self._find_bindings(state, rest_patterns)
                for rest_binding in rest_bindings:
                    combined = {**bindings, **rest_binding}
                    if self._is_consistent(combined):
                        bindings_list.append(combined)

        return bindings_list

    def _match_pattern(
        self, pattern_args: Tuple[str, ...], actual_args: Tuple[str, ...]
    ) -> Optional[Dict[str, str]]:
        """匹配模式。"""
        if len(pattern_args) != len(actual_args):
            return None

        bindings: Dict[str, str] = {}
        for p, a in zip(pattern_args, actual_args):
            if p.isupper():
                if p in bindings and bindings[p] != a:
                    return None
                bindings[p] = a
            elif p != a:
                return None

        return bindings

    def _is_consistent(self, _bindings: Dict[str, str]) -> bool:
        """检查绑定是否一致。"""
        return True


