class SymbolicEngine:
    """符号引擎。"""

    def __init__(self, rules: Optional[List[DeductionRule]] = None, extended: bool = True):
        """初始化符号引擎。"""
        if rules is None:
            if extended:
                self.rules = BUILTIN_RULES + EXTENDED_RULES
            else:
                self.rules = BUILTIN_RULES.copy()
        else:
            self.rules = rules
        self.state = ProofState()
        self.max_iterations = 100

    def reset(self):
        """重置引擎。"""
        self.state = ProofState()

    def add_statement(self, stmt_str: str, is_derived: bool = False) -> Statement:
        """添加命题。"""
        stmt = self._parse_statement(stmt_str)
        self.state.add(stmt, is_derived)
        return stmt

    def _parse_statement(self, stmt_str: str) -> Statement:
        """解析语句。"""
        stmt_str = stmt_str.strip()
        parts = stmt_str.split()
        if not parts:
            return Statement("", ())
        return Statement(parts[0], tuple(parts[1:]))

    def apply_rules(self) -> List[Statement]:
        """应用所有规则。"""
        new_statements = []
        for rule in self.rules:
            derived = rule.apply(self.state)
            for stmt in derived:
                self.state.add(stmt, is_derived=True)
                new_statements.append(stmt)
        return new_statements

    def deduce(self, max_steps: Optional[int] = None) -> int:
        """演绎推理。"""
        actual_max_steps = max_steps if max_steps is not None else self.max_iterations
        total_new = 0

        for _ in range(actual_max_steps):
            new = self.apply_rules()
            total_new += len(new)
            if not new:
                break

        return total_new

    def verify(self, stmt_str: str) -> bool:
        """验证命题。"""
        stmt = self._parse_statement(stmt_str)
        return self.state.contains(stmt)

    def can_derive(
        self, stmt_str: str, max_steps: Optional[int] = None
    ) -> Tuple[bool, List[Statement]]:
        """检查能否推导。"""
        if self.verify(stmt_str):
            return True, []

        original_state = ProofState(
            statements=self.state.statements.copy(), derived=self.state.derived.copy()
        )

        target = self._parse_statement(stmt_str)
        derivation_path = []

        actual_max_steps = max_steps if max_steps is not None else self.max_iterations

        for _ in range(actual_max_steps):
            new = self.apply_rules()
            derivation_path.extend(new)

            if self.state.contains(target):
                return True, derivation_path

        self.state = original_state
        return False, []

    def get_all_statements(self) -> List[str]:
        """获取所有命题。"""
        return [str(s) for s in self.state.statements]

    def get_derived_statements(self) -> List[str]:
        """获取推导命题。"""
        return [str(s) for s in self.state.derived]

    def get_rule_count(self) -> int:
        """获取规则数量。"""
        return len(self.rules)


